/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWOperacaoFolha-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'LCFNOM' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &LcfNom1.FromString(&GridStateDynamicFilter.Value) If not &LcfNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Descrição", "Começa com") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Descrição", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&LcfNom1) EndIf Case &DynamicFiltersSelector1 = !'LCFCOD' &LcfCod1.FromString(&GridStateDynamicFilter.Value) If not &LcfCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Código Operação" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &LcfCod1 EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'LCFNOM' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &LcfNom2.FromString(&GridStateDynamicFilter.Value) If not &LcfNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Descrição", "Começa com") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Descrição", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&LcfNom2) EndIf Case &DynamicFiltersSelector2 = !'LCFCOD' &LcfCod2.FromString(&GridStateDynamicFilter.Value) If not &LcfCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Código Operação" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &LcfCod2 EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'LCFNOM' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &LcfNom3.FromString(&GridStateDynamicFilter.Value) If not &LcfNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Descrição", "Começa com") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Descrição", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&LcfNom3) EndIf Case &DynamicFiltersSelector3 = !'LCFCOD' &LcfCod3.FromString(&GridStateDynamicFilter.Value) If not &LcfCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Código Operação" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &LcfCod3 EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Código" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Descrição" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Retornar R$" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "I.N.S.S. ?"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod LcfCod when &OrderedBy = 1 order LcfCod when &OrderedBy = 2 AND &OrderedDsc = False order (LcfCod) when &OrderedBy = 2 AND &OrderedDsc = True order LcfNom when &OrderedBy = 3 AND &OrderedDsc = False order (LcfNom) when &OrderedBy = 3 AND &OrderedDsc = True order LcfVlrPad when &OrderedBy = 4 AND &OrderedDsc = False order (LcfVlrPad) when &OrderedBy = 4 AND &OrderedDsc = True order LcfIsInss when &OrderedBy = 5 AND &OrderedDsc = False order (LcfIsInss) when &OrderedBy = 5 AND &OrderedDsc = True
using DSWWOperacaoFolha(&DynamicFiltersSelector1, &DynamicFiltersOperator1, &LcfNom1, &LcfCod1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2 , &DynamicFiltersOperator2, &LcfNom2, &LcfCod2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &DynamicFiltersOperator3 , &LcfNom3, &LcfCod3)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = LcfCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(LcfNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = '' do Case Case LcfVlrPad.ToString().Trim() = "X" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "- - -"
Case LcfVlrPad.ToString().Trim() = "A" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "SALARIO FIXO"
Case LcfVlrPad.ToString().Trim() = "B" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "SALARIO TOTAL"
Case LcfVlrPad.ToString().Trim() = "C" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "BONIFICACAO"
Case LcfVlrPad.ToString().Trim() = "D" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "OUTROS ACRESC."
Case LcfVlrPad.ToString().Trim() = "E" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "PERICULOSIDADE"
Case LcfVlrPad.ToString().Trim() = "F" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "INSALUBRIDADE"
Case LcfVlrPad.ToString().Trim() = "G" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "VALE TRANSPORTE"
Case LcfVlrPad.ToString().Trim() = "H" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "VALE REFEICAO"
EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = LcfIsInss.EnumerationDescription()
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWOperacaoFolhaGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWOperacaoFolhaGridState")) Else &GridState.FromXml(&Session.Get(!"WWOperacaoFolhaGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

parm(out:&Filename, out:&ErrorMessage);

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
